/* ============================================================
   CONFIGURACION - Variables del workflow
   Ir a: Workflow Settings > Variables y crear:
     IG_ACCESS_TOKEN  -> Token de acceso Meta (pagina)
     IG_PAGE_ID       -> ID numerico de tu cuenta Instagram
     SALES_LINK       -> Link de venta con descuento 50%
   ============================================================ */

const ACCESS_TOKEN = $vars.IG_ACCESS_TOKEN || 'CONFIGURA_IG_ACCESS_TOKEN_EN_VARIABLES';
const PAGE_ID      = $vars.IG_PAGE_ID      || 'CONFIGURA_IG_PAGE_ID_EN_VARIABLES';
const SALES_LINK   = $vars.SALES_LINK      || 'https://tu-link-de-venta.com';

/* ============================================================
   MEDIA - Sube tus archivos a Cloudinary y pega las URLs aqui
   ============================================================ */
const MEDIA = {
  VIDEO_GHOST_FACELESS: 'https://res.cloudinary.com/TU_CLOUD/video/upload/ghost_faceless.mp4',
  IMAGE_PACK_EXTREMO:   'https://res.cloudinary.com/TU_CLOUD/image/upload/pack_extremo.jpg',
  AUDIO_VENTAS:         'https://res.cloudinary.com/TU_CLOUD/video/upload/brandinelli_floreria.m4a',
  IMAGEN_ALUMNOS_1:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno1.jpg',
  IMAGEN_ALUMNOS_2:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno2.jpg',
  IMAGEN_ALUMNOS_3:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno3.jpg',
  IMAGEN_ALUMNOS_4:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno4.jpg',
  IMAGEN_ALUMNOS_5:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno5.jpg',
  IMAGEN_ALUMNOS_6:     'https://res.cloudinary.com/TU_CLOUD/image/upload/alumno6.jpg',
};

/* ============================================================
   HELPERS
   ============================================================ */
const delay = ms => new Promise(r => setTimeout(r, ms));

async function sendDM(userId, message) {
  const res = await fetch(`https://graph.facebook.com/v18.0/${PAGE_ID}/messages`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${ACCESS_TOKEN}`
    },
    body: JSON.stringify({
      recipient: { id: userId },
      message,
      messaging_type: 'RESPONSE'
    })
  });
  const data = await res.json();
  if (data.error) console.error('[sendDM error]', JSON.stringify(data.error));
  return data;
}

async function replyComment(commentId, text) {
  const res = await fetch(`https://graph.facebook.com/v18.0/${commentId}/replies`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${ACCESS_TOKEN}`
    },
    body: JSON.stringify({ message: text })
  });
  const data = await res.json();
  if (data.error) console.error('[replyComment error]', JSON.stringify(data.error));
  return data;
}

/* ============================================================
   PARSEO DEL EVENTO INSTAGRAM
   ============================================================ */
const body = $input.first().json.body || $input.first().json;
let eventType = 'unknown', senderId = null, senderName = 'amigo';
let messageText = '', commentId = null;

try {
  if (body.entry?.[0]) {
    const entry = body.entry[0];

    // DMs, Story Replies, Story Mentions
    if (entry.messaging?.[0]) {
      const msg = entry.messaging[0];
      senderId    = msg.sender?.id;
      messageText = msg.message?.text || '';
      const atts  = msg.message?.attachments || [];
      eventType   = atts.some(a => a.type === 'story_mention') ? 'story_mention'
                  : atts.some(a => a.type === 'story_reply')   ? 'story_reply'
                  : 'dm';
    }

    // Comentarios en posts/reels
    if (entry.changes?.[0]) {
      const change = entry.changes[0];
      if (change.field === 'comments') {
        eventType   = 'comment';
        senderId    = change.value?.from?.id;
        senderName  = change.value?.from?.username || change.value?.from?.name || 'amigo';
        commentId   = change.value?.id;
        messageText = change.value?.text || '';
      } else if (change.field === 'mentions') {
        eventType  = 'story_mention';
        senderId   = change.value?.from?.id || change.value?.commenter_id;
        senderName = change.value?.from?.username || 'amigo';
      }
    }
  }
} catch(e) { console.error('[Parse error]', e.message); }

if (!senderId) return [{ json: { status: 'no_sender_id' } }];

/* ============================================================
   STATE MACHINE - Gestiona el estado del funnel por usuario
   ============================================================ */
const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};
if (!staticData.users[senderId]) {
  staticData.users[senderId] = { state: 0, name: senderName, commentId: null };
}

const user = staticData.users[senderId];
const text = (messageText || '').toLowerCase().trim();
if (senderName && senderName !== 'amigo') user.name = senderName;
const name = user.name || 'amigo';

// Keywords que disparan el funnel
const KEYWORDS = ['nexus', 'informacion', 'información', 'obtener', 'informações', 'info', 'quiero', 'más info'];
const hasKeyword = KEYWORDS.some(k => text.includes(k));

let action = 'none';

if (['comment', 'story_mention', 'story_reply'].includes(eventType)) {
  action        = 'send_step_0';
  user.state    = 1;
  user.commentId = commentId;
} else if (eventType === 'dm') {
  if (user.state === 0 || hasKeyword) {
    action = 'send_step_0'; user.state = 1;
  } else if (user.state === 1 && (text.includes('me gustar') || text.includes('\u{1F4AA}'))) {
    action = 'send_step_1'; user.state = 2;
  } else if (user.state === 2 && (text.includes('me gustar') || text.includes('\u{1F4AA}'))) {
    action = 'send_step_2'; user.state = 3;
  } else if (user.state === 3 && (text.includes('si elias') || text.includes('sí elias') || text.includes('\u{1F92F}'))) {
    action = 'send_step_3'; user.state = 4;
  } else if (user.state === 4 && (text.includes('si elias') || text.includes('sí elias'))) {
    action = 'send_step_4'; user.state = 5;
  }
}

staticData.users[senderId] = user;

if (action === 'none') {
  return [{ json: { status: 'no_action', state: user.state, eventType } }];
}

/* ============================================================
   PASO 0 - Mensaje inicial (disparado por comentario/story/keyword)
   ============================================================ */
if (action === 'send_step_0') {

  // Responder al comentario publicamente
  if (eventType === 'comment' && commentId) {
    await replyComment(commentId, `Hola ${name}! Te acabo de enviar un mensaje privado con mas informacion! \u{1F680}`);
    await delay(600);
  }

  await sendDM(senderId, {
    text: `Hola ${name}, gracias por tu interes en querer emprender! \u{1F91D}\n\nEstoy emocionado de compartir mas detalles contigo de como es que hoy en dia podes generar mas ingresos con tus redes sociales.\n\nConoces ya sobre negocios digitales? Por favor elegí una respuesta de aqui abajo \u{1F447}`,
    quick_replies: [
      { content_type: 'text', title: 'me gustaría Elias \u{1F4AA}', payload: 'STEP1_YES' }
    ]
  });
}

/* ============================================================
   PASO 1 - METODO GHOST FACELESS + Video
   ============================================================ */
else if (action === 'send_step_1') {

  await sendDM(senderId, {
    text: `Genial! Te paso a comentar que es METODO GHOST FACELESS \u{1F47B}\n\nEste metodo de negocio permite que puedas tener un producto digital YA CREADO Y LISTO PARA DEJARTE GANANCIAS desde la primera semana GRACIAS A LAS CLASES VIRTUALES dentro del grupo para ayudarte a poner en practica los 5 pasos del negocio.\n\nTe imaginas la posibilidad de hacer 2000 USD extra por mes? \u{1F92F} Solo subiendo contenido en imagen o video previamente creado! Todo esto podes verlo en mi destacada VIP \u{1F446}`
  });
  await delay(1000);

  await sendDM(senderId, {
    attachment: {
      type: 'video',
      payload: { url: MEDIA.VIDEO_GHOST_FACELESS, is_reusable: true }
    }
  });
  await delay(1500);

  await sendDM(senderId, {
    text: `Aca podes ver como recibo pagos en automatico y es lo que quiero que aprendas hoy... Te gustaria? \u{1F680}`,
    quick_replies: [
      { content_type: 'text', title: 'me gustaría Elias \u{1F4AA}', payload: 'STEP2_YES' }
    ]
  });
}

/* ============================================================
   PASO 2 - Pack Extremo
   ============================================================ */
else if (action === 'send_step_2') {

  await sendDM(senderId, {
    text: `Estas listo para convertirte en un maestro del marketing y alcanzar tus metas? Con el Pack Extremo, la puerta al exito se abre de par en par! \u{1F680}\n\nEste pack es tu arma secreta para dominar el juego del marketing digital. Te damos todo lo que necesitas para generar 2.000 dolares al mes. Si, leiste bien! \u{1F929}\n\nDentro del Pack Extremo encontraras:\n\n\u{1F5D3} Guias de 90 dias con contenido irresistible para cautivar a tu audiencia.\n\u{1F680} Planes de lanzamiento que te haran despegar como un cohete.\n\u{1F9F2} 101 Llamados a la accion que te haran ganar clientes como pan caliente.\n\u{1F4A5} 101 Ganchos para Reels que te haran viral en cuestion de segundos.\n\u{1F3AC} Pack de videos Faceless de lujo para que tu cuenta crezca como la espuma.\n\nY que crees? Todo esto por menos de 30 USD! \u{1F92F}`
  });
  await delay(1000);

  await sendDM(senderId, {
    attachment: {
      type: 'image',
      payload: { url: MEDIA.IMAGE_PACK_EXTREMO, is_reusable: true }
    }
  });
  await delay(1000);

  await sendDM(senderId, {
    text: `Te gustaria ver resultados de alumnos ya ganando con el Pack Emprender? \u{1F440}`,
    quick_replies: [
      { content_type: 'text', title: 'si Elias!! \u{1F92F}', payload: 'STEP3_YES' }
    ]
  });
}

/* ============================================================
   PASO 3 - Resultados de alumnos (6 imagenes)
   ============================================================ */
else if (action === 'send_step_3') {

  await sendDM(senderId, { text: 'TE DEJO ACA DEBAJO GANANCIAS DE ALUMNOS \u{1F447}\u{1F447}' });
  await delay(500);

  for (const key of ['IMAGEN_ALUMNOS_1','IMAGEN_ALUMNOS_2','IMAGEN_ALUMNOS_3','IMAGEN_ALUMNOS_4','IMAGEN_ALUMNOS_5','IMAGEN_ALUMNOS_6']) {
    await sendDM(senderId, {
      attachment: { type: 'image', payload: { url: MEDIA[key], is_reusable: true } }
    });
    await delay(800);
  }

  await sendDM(senderId, {
    text: 'TE GUSTARIA COMENZAR Y SER UNO DE ELLOS? TAMBIEN VAS A RECIBIR LA FORMULA DE MI BOT AUTOMATICO DE GANANCIAS \u{1F916}\u{1F4B0}',
    quick_replies: [
      { content_type: 'text', title: 'SI ELIAS!!', payload: 'STEP4_YES' }
    ]
  });
}

/* ============================================================
   PASO 4 - Audio + Link de venta
   ============================================================ */
else if (action === 'send_step_4') {

  await sendDM(senderId, { text: `${name.toUpperCase()}\nESCUCHA ATENTAMENTE ESTE AUDIO: \u{1F3A7}` });
  await delay(500);

  await sendDM(senderId, {
    attachment: {
      type: 'audio',
      payload: { url: MEDIA.AUDIO_VENTAS, is_reusable: true }
    }
  });
  await delay(2000);

  await sendDM(senderId, {
    text: `AHORA SI PASEMOS A LA MEJOR PARTE \u{1F525}\n\nEn la que te unis a NUESTRA FAMILIA DE EMPRENDEDORES 2025 \u{1F4AA}\n\nTe dejo el siguiente link a nuestra pagina ya CON EL DESCUENTO DEL 50% \u{1F447}\n\n${SALES_LINK}`
  });
}

return [{ json: { status: 'ok', action, senderId, state: user.state } }];
